To implement a solution for the given problem in C++, we'll follow the approach that involves Dijkstra's algorithm to calculate the shortest paths from the headquarters (office 1) to all other offices, testing each fiber connection's necessity by temporarily removing it. Here is a C++ code snippet that embodies this solution:

```cpp
#include <bits/stdc++.h>
using namespace std;

const long long INF = 1e18;

// Graph representation using adjacency list
vector<pair<int, long long>> adj[100005]; // Pair: (neighbor, weight)

// Custom comparator for priority queue
struct Comparator {
    bool operator()(const pair<int, long long>& a, const pair<int, long long>& b) {
        return a.second > b.second;
    }
};

vector<long long> dijkstra(int source, int n) {
    vector<long long> distance(n + 1, INF);
    distance[source] = 0;
    priority_queue<pair<int, long long>, vector<pair<int, long long>>, Comparator> pq;
    pq.push({source, 0});

    while (!pq.empty()) {
        int a = pq.top().first;
        long long d = pq.top().second;
        pq.pop();

        if (d > distance[a]) continue;

        for (auto u : adj[a]) {
            int b = u.first;
            long long w = u.second;

            if (distance[a] + w < distance[b]) {
                distance[b] = distance[a] + w;
                pq.push({b, distance[b]});
            }
        }
    }

    return distance;
}

int main() {
    int n, m, k;
    cin >> n >> m >> k;

    for (int i = 0; i < m; i++) {
        int a, b;
        long long l;
        cin >> a >> b >> l;
        adj[a].push_back({b, l});
        adj[b].push_back({a, l});
    }

    vector<pair<int, long long>> fiber_edges;
    for (int i = 0; i < k; i++) {
        int c;
        long long p;
        cin >> c >> p;
        fiber_edges.push_back({c, p});
        // Add fiber connections to the adjacency list
        adj[1].push_back({c, p});
        adj[c].push_back({1, p});
    }

    // Calculate shortest paths with all fiber connections
    vector<long long> original_distances = dijkstra(1, n);

    int removable = 0;
    for (auto& edge : fiber_edges) {
        // Remove fiber connection
        adj[1].erase(remove_if(adj[1].begin(), adj[1].end(), [&](const pair<int, long long>& p) { return p.first == edge.first && p.second == edge.second; }), adj[1].end());
        adj[edge.first].erase(remove_if(adj[edge.first].begin(), adj[edge.first].end(), [&](const pair<int, long long>& p) { return p.first == 1 && p.second == edge.second; }), adj[edge.first].end());

        // Recalculate shortest paths without this fiber connection
        vector<long long> new_distances = dijkstra(1, n);

        // If distances are unchanged for all nodes, the connection is removable
        if (new_distances == original_distances) {
            removable++;
        } else {
            // Add back the fiber connection as it affects shortest paths
            adj[1].push_back(edge);
            adj[edge.first].push_back({1, edge.second});
        }
    }

    cout << removable << endl;

    return 0;
}
```

This C++ code follows the approach of:
- Constructing a graph where offices are nodes and connections, both normal and fiber, are edges with their respective latencies.
- Calculating the shortest paths from the HQ to all offices.
- Iterating through each fiber connection, temporarily removing it, recalculating the shortest paths, and analyzing if the removal affects any shortest path latency.
- The final count of removable fiber connections is outputted. 

Bear in mind, the `remove_if` alongside `erase` is utilized to efficiently remove a specific edge representing a fiber connection from the adjacency list, which is necessary for testing each fiber connection's impact on shortest path calculations.

