#include <iostream>
#include <vector>
#include <limits>

using namespace std;

const long long INF = numeric_limits<long long>::max();

// Data structure to represent a connection
struct Connection {
    int to;
    long long latency;
};

// Global variables for simplicity
vector<vector<Connection>> graph;
int n, m, k;

// Dijkstra's algorithm in a simple form - O(n^2), suitable for beginners
vector<long long> dijkstra(int start) {
    vector<long long> dist(n + 1, INF);
    vector<bool> visited(n + 1, false);
    dist[start] = 0;

    for (int i = 1; i <= n; ++i) {
        int u = -1;

        // Find the unvisited vertex with the smallest distance
        for (int j = 1; j <= n; ++j) {
            if (!visited[j] && (u == -1 || dist[j] < dist[u])) {
                u = j;
            }
        }

        if (dist[u] == INF) break; // Remaining vertices are unreachable

        visited[u] = true;

        // Relaxation step
        for (const auto &edge : graph[u]) {
            long long alt = dist[u] + edge.latency;
            if (alt < dist[edge.to]) {
                dist[edge.to] = alt;
            }
        }
    }
    return dist;
}

int main() {
    cin >> n >> m >> k;
    graph.resize(n + 1);

    // Reading normal connections
    for (int i = 0; i < m; i++) {
        int a, b;
        long long latency;
        cin >> a >> b >> latency;
        graph[a].push_back({b, latency});
        graph[b].push_back({a, latency}); // Assuming bidirectional roads
    }

    // Reading fiber connections
