    }   

    // Calculate the shortest paths with all connections
    vector<long long> distancesWithAllFibers = dijkstra(1);

    // Check each fiber connection for its necessity
    int removableFibers = 0;
    for (const auto &fiber : fiberConnections) {
        // Remove fiber connection from the graph
        graph[1].pop_back();
        graph[fiber.to].pop_back();

        vector<long long> distancesWithoutFiber = dijkstra(1);

        // If removing fiber does not increase the distance, it is removable
        if (distancesWithoutFiber[fiber.to] == distancesWithAllFibers[fiber.to]) {
            removableFibers++;
        }

        // Add the fiber connection back for the next iteration
        graph[1].push_back(fiber);
        graph[fiber.to].push_back({1, fiber.latency});
    }

    cout << removableFibers << endl;

    return 0;
}
